2104	        List<WmAdSdfRatioConfigFuture> pendingList = sdfRatioConfigFutureRepository.selectLatestPendingByPartners(
2105	                activityId, Collections.singletonList(new PartnerKey(partnerId, partnerType)));
2106	        WmAdSdfRatioConfigFuture pendingConfig = pendingList.isEmpty() ? null : pendingList.get(0);
