2111	    private SdfRatioInfoDTO buildSdfRatioInfoDTO(SdfAdAccountActivity activity,
2112	                                                  SdfAdAccountSign sign,
2113	                                                  WmAdSdfRatioConfigFuture pendingConfig) {
2114	        Integer ratioMode = sign != null && isSign(sign) ? sign.getRatioMode() : activity.getRatioMode();
2115	        SdfRatioModeEnum mode = SdfRatioModeEnum.fromDb(ratioMode);
2116	
2117	        SdfRatioInfoDTO dto = new SdfRatioInfoDTO();
2118	        dto.setRatioMode(mode.getMode());
2119	
2120	        String pendingCashRatio = pendingConfig != null ? pendingConfig.getCashRatio().toPlainString() : null;
2121	
2122	        if (mode == SdfRatioModeEnum.FIXED) {
2123	            dto.setCurrentCashRatio(activity.getCashRatioDecimal().toPlainString());
2124	        } else if (mode == SdfRatioModeEnum.DYNAMIC) {
2125	            dto.setCurrentCashRatio(activity.getCashRatioDecimal().toPlainString());
2126	            dto.setPendingCashRatio(pendingCashRatio);
2127	
2128	            SdfRatioBounds bounds = resolveRatioBounds(activity);
2129	            dto.setRatioMin(bounds.min.stripTrailingZeros().toPlainString());
2130	            dto.setRatioMax(bounds.max.stripTrailingZeros().toPlainString());
2131	        } else if (mode == SdfRatioModeEnum.CUSTOM) {
2132	            BigDecimal currentRatio = (sign != null && isSign(sign))
2133	                    ? sign.getCashRatioDecimal()
2134	                    : activity.getCashRatioDecimal();
2135	            dto.setCurrentCashRatio(currentRatio.toPlainString());
2136	            dto.setPendingCashRatio(pendingCashRatio);
2137	
2138	            dto.setRatioMin(resolveRatioMin(activity).toPlainString());
2139	            dto.setRatioMax(resolveConfigCap().toPlainString());
2140	        }
2141	
2142	        return dto;
